import React, { useCallback, useEffect, useLayoutEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { ArrowRight, Clapperboard, FolderPlus, ImageIcon, Layers, Music2, RefreshCw, Scissors, Trash2, Type, X } from 'lucide-react';
import { cn } from '@/shared/components/ui/contracts/cn';
import type { Shot } from '@/domains/generation/types';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

interface ContextMenuState {
  x: number;
  y: number;
  clientX: number;
}

interface ClipActionProps {
  action: TimelineAction;
  clipMeta: ClipMeta;
  isSelected: boolean;
  isPrimary?: boolean;
  selectedClipIds?: string[];
  thumbnailSrc?: string;
  onSelect: (clipId: string, trackId: string) => void;
  onDoubleClickAsset?: (assetKey: string) => void;
  onSplitHere?: (clipId: string, clientX: number) => void;
  onSplitClipsAtPlayhead?: (clipIds: string[]) => void;
  onDeleteClip?: (clipId: string) => void;
  onDeleteClips?: (clipIds: string[]) => void;
  onToggleMuteClips?: (clipIds: string[]) => void;
  /** True when the clip's file no longer matches the generation's current primary variant */
  isVariantStale?: boolean;
  /** True when the clip is linked to a generation (enables "Update to current variant" in menu) */
  isGenerationAsset?: boolean;
  onUpdateVariant?: () => void;
  onDismissStale?: () => void;
  canCreateShotFromSelection?: boolean;
  onCreateShotFromSelection?: () => Promise<Shot | null>;
  onGenerateVideoFromSelection?: () => void | Promise<void>;
  onNavigateToShot?: (shot: Shot) => void;
  onOpenGenerateVideo?: (shot: Shot) => void;
  isCreatingShot?: boolean;
}

const menuItemClassName = 'relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground';
const destructiveMenuItemClassName = `${menuItemClassName} hover:bg-destructive hover:text-destructive-foreground`;
const disabledMenuItemClassName = 'disabled:cursor-wait disabled:opacity-60';

type ClipContextMenuProps = Pick<ClipActionProps, 'isGenerationAsset' | 'onUpdateVariant' | 'isVariantStale' | 'onDismissStale' | 'onSplitHere' | 'onToggleMuteClips' | 'onSplitClipsAtPlayhead' | 'onCreateShotFromSelection' | 'onGenerateVideoFromSelection' | 'onNavigateToShot' | 'onOpenGenerateVideo' | 'isCreatingShot' | 'onDeleteClip' | 'onDeleteClips'> & { actionId: string; contextMenu: ContextMenuState; menuRef: React.RefObject<HTMLDivElement | null>; closeMenu: () => void; hasBatchSelection: boolean; selectedClipIds: string[]; showShotActions: boolean; hasActionsBeforeShotSection: boolean; };
type ClipContextMenuItemProps = { icon: React.ComponentType<{ className?: string }>; onClick: () => void; children: React.ReactNode; disabled?: boolean; destructive?: boolean; suffix?: React.ReactNode; };

function ClipContextMenuItem({ icon: Icon, onClick, children, disabled = false, destructive = false, suffix }: ClipContextMenuItemProps) {
  return (
    <button
      type="button"
      className={cn(destructive ? destructiveMenuItemClassName : menuItemClassName, disabled && disabledMenuItemClassName)}
      onClick={onClick}
      disabled={disabled}
    >
      <Icon className="h-4 w-4" />
      {children}
      {suffix}
    </button>
  );
}

function ClipContextMenu(props: ClipContextMenuProps) {
  const [adjusted, setAdjusted] = useState<{ x: number; y: number } | null>(null);
  const [createdShot, setCreatedShot] = useState<Shot | null>(null);
  const [isCreatingLocal, setIsCreatingLocal] = useState(false);

  useLayoutEffect(() => {
    if (!props.menuRef.current) {
      setAdjusted(null);
      return;
    }
    const rect = props.menuRef.current.getBoundingClientRect();
    const pad = 8;
    const x = Math.min(props.contextMenu.x, window.innerWidth - rect.width - pad);
    const y = Math.min(props.contextMenu.y, window.innerHeight - rect.height - pad);
    setAdjusted({ x: Math.max(pad, x), y: Math.max(pad, y) });
  }, [props.contextMenu.x, props.contextMenu.y, props.menuRef]);

  // Stop native mousedown from reaching the document-level click-outside listener.
  // Portal DOM hierarchy doesn't match the React tree, so Node.contains() can
  // return false for elements that ARE visually inside the menu.
  useEffect(() => {
    const el = props.menuRef.current;
    if (!el) return;
    const stop = (e: MouseEvent) => e.stopPropagation();
    el.addEventListener('mousedown', stop);
    return () => el.removeEventListener('mousedown', stop);
  }, [props.menuRef]);

  const handleCreateShot = useCallback(async () => {
    if (!props.onCreateShotFromSelection) return;
    setIsCreatingLocal(true);
    const shot = await props.onCreateShotFromSelection();
    setIsCreatingLocal(false);
    if (shot) {
      setCreatedShot(shot);
    }
  }, [props.onCreateShotFromSelection]);

  const pos = adjusted ?? props.contextMenu;

  return createPortal(
    <div
      ref={props.menuRef}
      className="fixed z-50 min-w-[10rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95"
      style={{ left: pos.x, top: pos.y }}
    >
      {!props.hasBatchSelection && props.isGenerationAsset && props.onUpdateVariant && (
        <ClipContextMenuItem icon={RefreshCw} onClick={() => { props.onUpdateVariant?.(); props.closeMenu(); }}>
          Update to current variant
        </ClipContextMenuItem>
      )}
      {!props.hasBatchSelection && props.isVariantStale && props.onDismissStale && (
        <ClipContextMenuItem icon={X} onClick={() => { props.onDismissStale?.(); props.closeMenu(); }}>
          Dismiss reminder
        </ClipContextMenuItem>
      )}
      {((props.isGenerationAsset && props.onUpdateVariant) || (props.isVariantStale && props.onDismissStale)) && !props.hasBatchSelection && (
        <div className="my-1 h-px bg-border" />
      )}
      {!props.hasBatchSelection && props.onSplitHere && (
        <ClipContextMenuItem icon={Scissors} onClick={() => { props.onSplitHere?.(props.actionId, props.contextMenu.clientX); props.closeMenu(); }}>
          Split Here
        </ClipContextMenuItem>
      )}
      {props.hasBatchSelection && props.onToggleMuteClips && (
        <ClipContextMenuItem icon={Music2} onClick={() => { props.onToggleMuteClips?.(props.selectedClipIds); props.closeMenu(); }}>
          Mute/Unmute {props.selectedClipIds.length} clips
        </ClipContextMenuItem>
      )}
      {props.hasBatchSelection && props.onSplitClipsAtPlayhead && (
        <ClipContextMenuItem icon={Scissors} onClick={() => { props.onSplitClipsAtPlayhead?.(props.selectedClipIds); props.closeMenu(); }}>
          Split {props.selectedClipIds.length} clips at playhead
        </ClipContextMenuItem>
      )}
      {props.showShotActions && props.hasActionsBeforeShotSection && <div className="my-1 h-px bg-border" />}
      {props.showShotActions && !createdShot && props.onCreateShotFromSelection && (
        <ClipContextMenuItem icon={FolderPlus} onClick={() => void handleCreateShot()} disabled={isCreatingLocal || props.isCreatingShot}>
          {isCreatingLocal ? 'Creating…' : 'Create Shot'}
        </ClipContextMenuItem>
      )}
      {props.showShotActions && createdShot && props.onNavigateToShot && (
        <ClipContextMenuItem icon={ArrowRight} onClick={() => { props.onNavigateToShot?.(createdShot); props.closeMenu(); }}>
          Jump to {createdShot.name}
        </ClipContextMenuItem>
      )}
      {props.showShotActions && createdShot && props.onOpenGenerateVideo && (
        <ClipContextMenuItem icon={Clapperboard} onClick={() => { props.onOpenGenerateVideo?.(createdShot); props.closeMenu(); }}>
          Generate Video
        </ClipContextMenuItem>
      )}
      {props.showShotActions && !createdShot && props.onGenerateVideoFromSelection && (
        <ClipContextMenuItem icon={Clapperboard} onClick={() => { props.closeMenu(); void props.onGenerateVideoFromSelection?.(); }} disabled={props.isCreatingShot}>
          Generate Video
        </ClipContextMenuItem>
      )}
      {props.hasBatchSelection && props.onDeleteClips ? (
        <ClipContextMenuItem
          icon={Trash2}
          onClick={() => { props.onDeleteClips?.(props.selectedClipIds); props.closeMenu(); }}
          destructive
          suffix={<span className="ml-auto text-xs tracking-widest opacity-60">Del</span>}
        >
          Delete {props.selectedClipIds.length} clips
        </ClipContextMenuItem>
      ) : props.onDeleteClip && (
        <ClipContextMenuItem
          icon={Trash2}
          onClick={() => { props.onDeleteClip?.(props.actionId); props.closeMenu(); }}
          destructive
          suffix={<span className="ml-auto text-xs tracking-widest opacity-60">Del</span>}
        >
          Delete Clip
        </ClipContextMenuItem>
      )}
    </div>,
    document.body,
  );
}

export function ClipAction({
  action,
  clipMeta,
  isSelected,
  isPrimary = false,
  selectedClipIds = [],
  thumbnailSrc,
  onSelect,
  onDoubleClickAsset,
  onSplitHere,
  onSplitClipsAtPlayhead,
  onDeleteClip,
  onDeleteClips,
  onToggleMuteClips,
  isVariantStale,
  isGenerationAsset,
  onUpdateVariant,
  onDismissStale,
  canCreateShotFromSelection = false,
  onCreateShotFromSelection,
  onGenerateVideoFromSelection,
  onNavigateToShot,
  onOpenGenerateVideo,
  isCreatingShot = false,
}: ClipActionProps) {
  const [contextMenu, setContextMenu] = useState<ContextMenuState | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Snapshot shot-creation state when the menu opens so that re-renders
  // (e.g. from EffectRegistry) can't remove the items while the menu is visible.
  const shotActionsSnapshotRef = useRef<{
    showShotActions: boolean;
    onCreateShotFromSelection?: () => Promise<Shot | null>;
    onGenerateVideoFromSelection?: () => void | Promise<void>;
    onNavigateToShot?: (shot: Shot) => void;
    onOpenGenerateVideo?: (shot: Shot) => void;
    isCreatingShot: boolean;

}, [selectClip, setSelectedTrackId]);

const pixelsPerSecond = scaleWidth / scale;

const selectionShotCreationState = useMemo(() => {
  if (!data) {
    return { canCreateShot: false, generationIds: [] as string[] };
  }

  return resolveSelectedGenerationIdsForShotCreation({
    rows: data.rows,
    meta: data.meta,
    registry: data.registry,
    selectedClipIds,
  });
}, [data, selectedClipIds]);

const handleCreateShotFromSelection = useCallback(async (): Promise<Shot | null> => {
  console.log('[ShotCreate] handleCreateShotFromSelection', {
    canCreateShot: selectionShotCreationState.canCreateShot,
    generationIds: selectionShotCreationState.generationIds,
  });
  if (!selectionShotCreationState.canCreateShot) {
    return null;
  }

  const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
  console.log('[ShotCreate] createShot result', result);
  if (result?.shot) {
    return result.shot;
  }
  return null;
}, [createShot, selectionShotCreationState]);

const handleGenerateVideoFromSelection = useCallback(async () => {
  if (!selectionShotCreationState.canCreateShot) {
    return;
  }

  const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
  if (!result?.shotId) {
    return;
  }

  const createdShot = result.shot ?? shots?.find((shot) => shot.id === result.shotId) ?? null;
  if (createdShot) {
    setVideoModalShot(createdShot);
  }
}, [createShot, selectionShotCreationState, shots]);

const handleNavigateToShot = useCallback((shot: Shot) => {
  navigateToShot(shot, { isNewlyCreated: true });
}, [navigateToShot]);

const handleOpenGenerateVideo = useCallback((shot: Shot) => {
  setVideoModalShot(shot);
}, []);

const clientXToTime = useCallback((clientX: number): number => {
  const wrapper = timelineWrapperRef.current;
  if (!wrapper) return 0;
  const editArea = wrapper.querySelector<HTMLElement>('.timeline-canvas-edit-area');
  const grid = editArea;
  const rect = (editArea ?? wrapper).getBoundingClientRect();
  const scrollLeft = grid?.scrollLeft ?? 0;
  return Math.max(0, (clientX - rect.left + scrollLeft - TIMELINE_START_LEFT) / pixelsPerSecond);
}, [pixelsPerSecond, timelineWrapperRef]);

const handleSplitClipHere = useCallback((clipId: string, clientX: number) => {
  const time = clientXToTime(clientX);
  handleSplitClipAtTime(clipId, time);
}, [clientXToTime, handleSplitClipAtTime]);

const getActionRender = useCallback((action: TimelineAction) => {
  const clipMeta = data?.meta[action.id];
  if (!clipMeta) {
    return null;
  }

  const clipWidthPx = (action.end - action.start) * pixelsPerSecond;
  const thumbnailSrc = clipWidthPx >= 40 ? thumbnailMap[action.id] : undefined;
  const assetKey = clipMeta.asset;
  const isStale = assetKey ? staleAssetKeys.has(assetKey) : false;
  const isDismissed = assetKey ? dismissedAssetKeys.has(assetKey) : false;
  const isGenAsset = assetKey ? generationAssetKeys.has(assetKey) : false;

  return (
    <ClipAction
      action={action}
      clipMeta={clipMeta}
      isSelected={isClipSelected(action.id)}
      isPrimary={primaryClipId === action.id}
      selectedClipIds={[...selectedClipIds]}
      thumbnailSrc={thumbnailSrc}
      onSelect={handleClipSelect}
      onDoubleClickAsset={onDoubleClickAsset}
      onSplitHere={handleSplitClipHere}
      onSplitClipsAtPlayhead={handleSplitClipsAtPlayhead}
      onDeleteClips={handleDeleteClips}
      onDeleteClip={handleDeleteClip}
      onToggleMuteClips={handleToggleMuteClips}
